══════════════════════════════════════════════════════════════ // ORA Studio — Edge Function Server (Hono + KV + INLINE AI) // ALL AI logic inlined — NO external imports, NO dynamic import // ══════════════════════════════════════════════════════════════ import { Hono } from "npm:hono@4.4.2"; import { createClient } from "jsr:@supabase/supabase-js@2.49.8"; import * as kv from "./kv_store.tsx"; console.log("[boot] ORA server starting (inline AI)..."); const app = new Hono().basePath("/make-server-cad57f79"); // ── CORS — fully manual, guaranteed headers on EVERY response ── const CORS_HEADERS: Record<string, string> = { "Access-Control-Allow-Origin": "", "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS", "Access-Control-Allow-Headers": "Content-Type, Authorization, X-User-Token, apikey", "Access-Control-Max-Age": "86400", }; app.use("", async (c, next) => { // Handle preflight immediately — no auth, no routing if (c.req.method === "OPTIONS") { return new Response(null, { status: 204, headers: CORS_HEADERS }); } await next(); // Inject CORS headers into every non-OPTIONS response try { for (const [k, v] of Object.entries(CORS_HEADERS)) { c.res.headers.set(k, v); } } catch { // Response headers might be immutable — rebuild response c.res = new Response(c.res.body, { status: c.res.status, statusText: c.res.statusText, headers: { ...Object.fromEntries(c.res.headers.entries()), ...CORS_HEADERS, }, }); } }); // ── Global error handler — ensures CORS headers on ALL error responses ── app.onError((err, c) => { const msg = err instanceof Error ? err.message : String(err); console.log([onError] ${msg}); return new Response( JSON.stringify({ success: false, error: msg }), { status: 500, headers: { "Content-Type": "application/json", ...CORS_HEADERS, }, } ); }); // ── BODY PARSER + TOKEN EXTRACTOR ── // Reads body once, caches parsed result, extracts token for auth. // This handles both Content-Type: application/json AND text/plain (CORS-safe). app.use("", async (c, next) => { if (c.req.method === "POST" || c.req.method === "PUT" || c.req.method === "DELETE") { try { const cloned = c.req.raw.clone(); const text = await cloned.text(); if (text) { const body = JSON.parse(text); c.set("parsedBody", body); if (body?._token) { c.set("userToken", body.token); } } } catch { / not JSON or no body — ignore / } } await next(); }); // ── REQUEST LOGGER ── app.use("", async (c, next) => { const method = c.req.method; const path = c.req.path; console.log([REQ] ${method} ${path} at ${new Date().toISOString()}); const t0 = Date.now(); await next(); console.log([RES] ${method} ${path} -> ${c.res.status} (${Date.now() - t0}ms)); }); // ── HEALTH CHECK (earliest route — tests that function booted) ── app.get("/health", (c) => c.json({ ok: true, ts: Date.now() })); // ── Supabase Admin Client ──────────────────────────────────── function supabaseAdmin() { return createClient( Deno.env.get("SUPABASE_URL")!, Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!, ); } // ── Auth Helpers ───────────────────────────────────────────── const ADMIN_EMAIL = Deno.env.get("ADMIN_EMAIL") || "romainortel@gmail.com"; // FIX: depuis env interface AuthUser { id: string; email: string; } // Fast JWT decode (no verification needed — Supabase gateway already validated the token) function decodeJwtPayload(token: string): any { try { const parts = token.split("."); if (parts.length !== 3) return null; const payload = parts[1]; // Base64url decode const base64 = payload.replace(/-/g, "+").replace(//g, "/"); const padded = base64 + "=".repeat((4 - base64.length % 4) % 4); const decoded = atob(padded); return JSON.parse(decoded); } catch { return null; } } async function getUser(c: any): Promise<AuthUser | null> { // Token sources (priority order): // 1. token extracted by body-parser middleware (avoids CORS & large header issues) // 2. token query parameter (for GET requests in CORS-safe mode) // 3. X-User-Token header (legacy) // 4. Authorization header (may be anon key → returns null) const token = c.get?.("userToken") || c.req.query("token") || c.req.header("X-User-Token") || c.req.header("Authorization")?.split(" ")[1]; if (!token) return null; try { // Fast path: decode JWT locally (gateway already validated it) const payload = decodeJwtPayload(token); if (payload?.sub && payload?.email) { console.log("[getUser] JWT decoded locally, user:", payload.sub); return { id: payload.sub, email: payload.email }; } // Token is not a JWT (e.g. anon key) — skip console.log("[getUser] Token is not a valid JWT, returning null"); return null; } catch (err) { console.log("[getUser] exception:", err); return null; } } async function requireAuth(c: any): Promise<AuthUser> { const user = await getUser(c); if (!user) throw new Error("Unauthorized"); return user; } async function requireAdmin(c: any): Promise<AuthUser> { const user = await requireAuth(c); const profile = await kv.get(user:${user.id}); if (user.email.toLowerCase() !== ADMIN_EMAIL && profile?.role !== "admin") { throw new Error("Forbidden"); } return user; } // ── Credit Helpers ─────────────────────────────────────────── const PLAN_CREDITS: Record<string, number> = { free: 50, generate: 500, studio: 2500 }; // Timeout wrapper for KV operations (prevents hanging on DB issues) function withTimeout<T>(promise: Promise<T>, ms: number, label: string): Promise<T> { return Promise.race([ promise, new Promise<T>((, reject) => setTimeout(() => reject(new Error(${label} timeout (${ms}ms))), ms) ), ]); } async function getOrCreateProfile(userId: string, email: string, name?: string) { const t0 = Date.now(); let profile = await withTimeout(kv.get(user:${userId}), 5_000, "kv.get profile"); console.log([getOrCreateProfile] kv.get took ${Date.now() - t0}ms); if (!profile) { const isAdmin = email.toLowerCase() === ADMIN_EMAIL; profile = { userId, email, name: name || email.split("@")[0], role: isAdmin ? "admin" : "user", plan: isAdmin ? "studio" : "free", credits: isAdmin ? 999999 : PLAN_CREDITS.free, creditsUsed: 0, company: "", jobTitle: "", createdAt: new Date().toISOString(), lastLoginAt: new Date().toISOString(), }; await withTimeout(kv.set(user:${userId}, profile), 5_000, "kv.set new profile"); } return profile; } async function deductCredit(userId: string, amount = 1): Promise<boolean> { try { const profile = await withTimeout(kv.get(user:${userId}), 3_000, "kv.get deduct"); if (!profile) return true; // laisser passer si KV lent if (profile.role === "admin") return true; const remaining = (profile.credits || 0) - (profile.creditsUsed || 0); if (remaining < amount) return false; profile.creditsUsed = (profile.creditsUsed || 0) + amount; kv.set(user:${userId}, profile).catch(() => {}); // fire-and-forget return true; } catch { return true; // KV timeout → laisser passer } } async function logEvent(type: string, details: any) { try { const id = log:${Date.now()}-${Math.random().toString(36).slice(2, 8)}; await kv.set(id, { id, type, details, timestamp: new Date().toISOString() }); } catch (e) { console.log("[logEvent] failed:", e); } } // ══════════════════════════════════════════════════════════════ // COST TRACKING — per-provider cost & revenue logging // ══════════════════════════════════════════════════════════════ const PROVIDER_COSTS: Record<string, number> = { "apipod/gpt-4o": 0.015, "apipod/gpt-5": 0.025, "apipod/gpt-5.2": 0.030, "apipod/claude-sonnet-4-20250514": 0.018, "apipod/claude-3-5-sonnet-20241022": 0.015, "apipod/claude-haiku-4-20250514": 0.005, "apipod/claude-3-5-haiku-20241022": 0.004, "apipod/claude-opus-4-20250514": 0.075, "apipod/gemini-2.5-flash-preview-05-20": 0.005, "apipod/gemini-2.0-flash": 0.003, "apipod/gemini-3": 0.008, "luma/photon-1": 0.030, "luma/photon-flash-1": 0.015, "luma/ray-2": 0.150, "luma/ray-flash-2": 0.080, "replicate/meta/musicgen": 0.050, "kling/kling-v1-6-pro": 0.120, "kling/kling-v1-5-pro": 0.100, }; const CREDIT_VALUE_EUR = 0.10; const REVENUE_PER_TYPE: Record<string, number> = { text: 1 * CREDIT_VALUE_EUR, image: 2 * CREDIT_VALUE_EUR, video: 5 * CREDIT_VALUE_EUR, audio: 3 * CREDIT_VALUE_EUR, }; const USD_TO_EUR = 0.92; interface CostEntry { id: string; timestamp: string; type: "text" | "image" | "video" | "audio"; model: string; provider: string; costUsd: number; costEur: number; revenueEur: number; marginEur: number; latencyMs: number; userId: string; success: boolean; } async function logCost(entry: Omit<CostEntry, "id" | "timestamp" | "costEur" | "marginEur">) { try { const costEur = entry.costUsd * USD_TO_EUR; const marginEur = entry.revenueEur - costEur; const id = cost:${Date.now()}-${Math.random().toString(36).slice(2, 8)}; const full: CostEntry = { ...entry, id, timestamp: new Date().toISOString(), costEur: Math.round(costEur * 10000) / 10000, marginEur: Math.round(marginEur * 10000) / 10000 }; await kv.set(id, full); console.log([cost] ${entry.type}/${entry.provider}: cost=$${entry.costUsd} rev=EUR${entry.revenueEur} margin=EUR${full.marginEur}); } catch (e) { console.log("[logCost] failed:", e); } } function getProviderCost(provider: string, type: string): number { if (PROVIDER_COSTS[provider]) return PROVIDER_COSTS[provider]; const prefix = provider.split("/")[0]; if (prefix === "luma") return type === "video" ? 0.150 : 0.030; if (prefix === "replicate") return type === "audio" ? 0.050 : 0.005; if (prefix === "apipod") return 0.015; return 0.010; } // ══════════════════════════════════════════════════════════════ // INLINE AI — TEXT (APIPod), IMAGE (Luma Photon), VIDEO (Luma Ray), AUDIO (Replicate) // ══════════════════════════════════════════════════════════════ const APIPOD_BASE = "https://api.apipod.ai/v1"; const LUMA_BASE = "https://api.lumalabs.ai/dream-machine/v1"; // ── PROMPT ENHANCER — translates any language to English + enriches for image generation ── async function enhanceImagePrompt(rawPrompt: string): Promise<string> { const t0 = Date.now(); // Quick heuristic: if prompt looks already English and descriptive enough, skip const nonAscii = rawPrompt.replace(/[\x00-\x7F]/g, "").length; const isLikelyEnglish = nonAscii < rawPrompt.length * 0.15; const isAlreadyDetailed = rawPrompt.split(/\s+/).length > 12; if (isLikelyEnglish && isAlreadyDetailed) { console.log([enhancePrompt] Already English & detailed, skip (${rawPrompt.slice(0, 60)})); return rawPrompt; } try { const key = Deno.env.get("APIPOD_API_KEY"); if (!key) { console.log("[enhancePrompt] No API key, using raw"); return rawPrompt; } const res = await fetch(${APIPOD_BASE}/chat/completions, { method: "POST", headers: { "Content-Type": "application/json", Authorization: Bearer ${key} }, body: JSON.stringify({ model: "gpt-4o", messages: [ { role: "system", content: "You are an expert image prompt engineer. Your ONLY job is to translate the user's request into a single, detailed English image generation prompt. Output ONLY the prompt text — no quotes, no explanation, no preamble. Keep it under 120 words. Preserve the user's creative intent precisely. Add relevant visual details (lighting, composition, mood, style) that match the intent." }, { role: "user", content: rawPrompt }, ], max_tokens: 200, }), }); if (!res.ok) { console.log([enhancePrompt] APIPod ${res.status}, using raw); return rawPrompt; } const data = await res.json(); const enhanced = data.choices?.[0]?.message?.content?.trim(); if (enhanced && enhanced.length > 10) { console.log([enhancePrompt] OK (${Date.now() - t0}ms): "${rawPrompt.slice(0, 40)}" → "${enhanced.slice(0, 80)}"); return enhanced; } } catch (err) { console.log([enhancePrompt] error (${Date.now() - t0}ms): ${err}); } return rawPrompt; } function lumaHeaders(): Record<string, string> { const key = Deno.env.get("LUMA_API_KEY"); if (!key) throw new Error("LUMA_API_KEY not configured"); return { "Content-Type": "application/json", Authorization: Bearer ${key} }; } function apipodHeaders(): Record<string, string> { const key = Deno.env.get("APIPOD_API_KEY"); if (!key) throw new Error("APIPOD_API_KEY not configured"); return { "Content-Type": "application/json", Authorization: Bearer ${key} }; } // --- Text model registry --- // Model map — CORRECT APIPod model names (from their docs): // OpenAI: gpt-5, gpt-5.1-codex, gpt-5.1, gpt-4o // Anthropic: claude-4-5-sonnet, claude-4-5-opus, claude-4-5-haiku // Google: gemini-2.5-pro, gemini-3-pro-preview // Other: deepseek-v3.2, doubao-pro const textModelMap: Record<string, { apiModel: string; fallback?: string }> = { "gpt-4o": { apiModel: "gpt-4o" }, "gpt-5": { apiModel: "gpt-5", fallback: "gpt-4o" }, "gpt-5.1": { apiModel: "gpt-5.1", fallback: "gpt-5" }, "gpt-5.2": { apiModel: "gpt-5.1", fallback: "gpt-4o" }, "claude-sonnet": { apiModel: "claude-4-5-sonnet", fallback: "gpt-4o" }, "claude-haiku": { apiModel: "claude-4-5-haiku", fallback: "gpt-4o" }, "claude-opus": { apiModel: "claude-4-5-opus", fallback: "claude-4-5-sonnet" }, "gemini-pro": { apiModel: "gemini-2.5-pro", fallback: "gpt-4o" }, "gemini-3": { apiModel: "gemini-3-pro-preview", fallback: "gemini-2.5-pro" }, "ora-writer": { apiModel: "gpt-4o" }, "ora-code": { apiModel: "gpt-4o" }, "gpt-4o-code": { apiModel: "gpt-4o" }, "claude-code": { apiModel: "claude-4-5-sonnet", fallback: "gpt-4o" }, "gemini-code": { apiModel: "gemini-2.5-pro", fallback: "gpt-4o" }, "deepseek": { apiModel: "deepseek-v3.2", fallback: "gpt-4o" }, }; // --- Image model registry (Luma Photon) --- const imageModelMap: Record<string, { lumaModel: string; aspectRatio: string }> = { "ora-vision": { lumaModel: "photon-1", aspectRatio: "4:3" }, "photon-1": { lumaModel: "photon-1", aspectRatio: "4:3" }, "photon-flash-1": { lumaModel: "photon-flash-1", aspectRatio: "4:3" }, "seedream-v4.5": { lumaModel: "photon-1", aspectRatio: "4:3" }, "seedream-5-lite": { lumaModel: "photon-flash-1", aspectRatio: "4:3" }, "nano-banana": { lumaModel: "photon-flash-1", aspectRatio: "1:1" }, "dall-e": { lumaModel: "photon-1", aspectRatio: "1:1" }, "flux-pro": { lumaModel: "photon-1", aspectRatio: "4:3" }, }; // --- Video model registry (Luma Ray) --- const videoModelMap: Record<string, { lumaModel: string; aspectRatio: string }> = { "ora-motion": { lumaModel: "ray-2", aspectRatio: "16:9" }, "ray-2": { lumaModel: "ray-2", aspectRatio: "16:9" }, "ray-flash-2": { lumaModel: "ray-flash-2", aspectRatio: "16:9" }, "veo-3.1": { lumaModel: "ray-2", aspectRatio: "16:9" }, "sora-2": { lumaModel: "ray-2", aspectRatio: "16:9" }, "seedance-2.0": { lumaModel: "ray-2", aspectRatio: "16:9" }, "seedance-1.5-pro": { lumaModel: "ray-2", aspectRatio: "16:9" }, "seedance-1.0": { lumaModel: "ray-flash-2", aspectRatio: "16:9" }, "runway-gen3": { lumaModel: "ray-2", aspectRatio: "16:9" }, "pika": { lumaModel: "ray-flash-2", aspectRatio: "16:9" }, "sora": { lumaModel: "ray-2", aspectRatio: "16:9" }, }; // --- Audio model registry (Replicate MusicGen) --- const audioModels: Record<string, string> = { "ora-audio": "meta/musicgen", "musicgen": "meta/musicgen", "elevenlabs": "meta/musicgen", "suno": "meta/musicgen", "udio": "meta/musicgen", }; // ─ TEXT GENERATION (APIPod only) ───────────────────────────── // Uses APIPod model names with fallback chain + Promise.race timeout async function generateText(req: { prompt: string; model: string; systemPrompt?: string; maxTokens?: number }) { const mapping = textModelMap[req.model]; if (!mapping) throw new Error(Unknown text model: ${req.model}); const sys = req.systemPrompt || "You are a creative professional AI assistant."; const maxTok = req.maxTokens || 1024; const start = Date.now(); // Build chain: primary → fallback → gpt-4o (ultimate safe fallback) const chain: string[] = [mapping.apiModel]; if (mapping.fallback && mapping.fallback !== mapping.apiModel) chain.push(mapping.fallback); if (!chain.includes("gpt-4o")) chain.push("gpt-4o"); console.log([text] model=${req.model} → chain=${JSON.stringify(chain)}, prompt="${req.prompt.slice(0, 50)}...", maxTok=${maxTok}); let lastErr: Error | null = null; for (const apiModel of chain) { try { console.log([text] trying ${apiModel} (elapsed: ${Date.now() - start}ms)...); const fetchPromise = fetch(${APIPOD_BASE}/chat/completions, { method: "POST", headers: apipodHeaders(), body: JSON.stringify({ model: apiModel, messages: [{ role: "system", content: sys }, { role: "user", content: req.prompt }], max_tokens: maxTok, }), }).then(async (res) => { if (!res.ok) { const b = await res.text(); throw new Error(APIPod ${res.status}: ${b}); } const data = await res.json(); const text = data.choices?.[0]?.message?.content || ""; if (!text) throw new Error(Empty response from ${apiModel}); return { text, tokensUsed: data.usage?.total_tokens || 0 }; }); // 8s timeout per model attempt — fast fail, move to fallback const timeoutPromise = new Promise<never>((, reject) => setTimeout(() => reject(new Error(APIPod timeout (8s) for ${apiModel})), 8_000) ); const result = await Promise.race([fetchPromise, timeoutPromise]); console.log([text] ${apiModel} OK in ${Date.now() - start}ms, ${result.text.length} chars); return { model: req.model, provider: apipod/${apiModel}, text: result.text, tokensUsed: result.tokensUsed, latencyMs: Date.now() - start }; } catch (err) { lastErr = err instanceof Error ? err : new Error(String(err)); console.log([text] ${apiModel} FAILED (${Date.now() - start}ms): ${lastErr.message}); } } throw lastErr || new Error(All text models failed for ${req.model}); } // ── IMAGE GENERATION (Luma Photon — submit + polling) ── async function generateImage(req: { prompt: string; model: string }) { const mapping = imageModelMap[req.model]; if (!mapping) throw new Error(Unknown image model: ${req.model}); const start = Date.now(); console.log([image] model=${req.model} → Luma ${mapping.lumaModel}, aspect=${mapping.aspectRatio}); console.log([image] prompt="${req.prompt.slice(0, 80)}..."); // Step 1: Submit image generation const submitRes = await fetch(${LUMA_BASE}/generations/image, { method: "POST", headers: lumaHeaders(), body: JSON.stringify({ prompt: req.prompt, model: mapping.lumaModel, aspect_ratio: mapping.aspectRatio, }), }); if (!submitRes.ok) { const b = await submitRes.text(); throw new Error(Luma image submit ${submitRes.status}: ${b}); } const generation = await submitRes.json(); const genId = generation.id; if (!genId) throw new Error(Luma image: no generation id returned: ${JSON.stringify(generation).slice(0, 300)}); console.log([image] Luma generation submitted: ${genId}, state=${generation.state} (${Date.now() - start}ms)); // Step 2: Poll for completion (max 90s, every 3s) let elapsed = 0; while (elapsed < 90_000) { await new Promise(r => setTimeout(r, 3_000)); elapsed += 3_000; try { const pollRes = await fetch(${LUMA_BASE}/generations/${genId}, { headers: lumaHeaders(), }); if (!pollRes.ok) { console.log([image] poll ${pollRes.status} for ${genId} (${elapsed / 1000}s, continuing)); continue; } const pollData = await pollRes.json(); const state = pollData.state; console.log([image] poll ${genId}: state=${state} (${elapsed / 1000}s)); if (state === "completed") { const imageUrl = pollData.assets?.image; if (!imageUrl) throw new Error(Luma image completed but no URL: ${JSON.stringify(pollData).slice(0, 300)}); console.log([image] Luma ${mapping.lumaModel} OK in ${Date.now() - start}ms); return { model: req.model, provider: luma/${mapping.lumaModel}, imageUrl, latencyMs: Date.now() - start }; } if (state === "failed") { throw new Error(Luma image failed: ${pollData.failure_reason || "unknown"}); } // queued, dreaming → continue polling } catch (pollErr) { if (pollErr instanceof Error && (pollErr.message.startsWith("Luma image failed") || pollErr.message.startsWith("Luma image completed"))) throw pollErr; console.log([image] poll error (continuing): ${pollErr}); } } throw new Error(Luma image timeout (90s) for ${mapping.lumaModel}, generation=${genId}); } // ── IMAGE WITH REFERENCE (img2img — FAL primary, Runware/Luma fallback) ── async function generateImageWithRef(req: { prompt: string; model: string; imageRefUrl: string; strength?: number }) { const start = Date.now(); const strength = req.strength ?? 0.75; console.log([img2img] model=${req.model}, strength=${strength}, ref=${req.imageRefUrl.slice(0, 80)}); // Strategy 1: FAL img2img (fast, reliable) const falKey = Deno.env.get("FAL_API_KEY"); if (falKey) { const falModels = ["fal-ai/flux/dev/image-to-image", "fal-ai/flux-general/image-to-image"]; for (const falModel of falModels) { try { console.log([img2img] Trying FAL ${falModel}...); const res = await fetch(https://fal.run/${falModel}, { method: "POST", headers: { "Content-Type": "application/json", Authorization: Key ${falKey} }, body: JSON.stringify({ prompt: req.prompt, image_url: req.imageRefUrl, strength, image_size: "landscape_4_3", num_images: 1, enable_safety_checker: true, num_inference_steps: 28, }), }); if (!res.ok) { const b = await res.text(); console.log([img2img] FAL ${falModel} ${res.status}: ${b.slice(0, 200)}); continue; } const data = await res.json(); const imageUrl = data.images?.[0]?.url; if (imageUrl) { console.log([img2img] FAL ${falModel} OK in ${Date.now() - start}ms); return { model: req.model, provider: fal-img2img/${falModel}, imageUrl, latencyMs: Date.now() - start }; } } catch (err) { console.log([img2img] FAL ${falModel} error: ${err}); } } } // Strategy 2: Runware img2img const rwKey = Deno.env.get("RUNWARE_IMAGE_API_KEY"); if (rwKey) { try { console.log([img2img] Trying Runware img2img...); const ctrl = new AbortController(); const timer = setTimeout(() => ctrl.abort(), 30_000); const res = await fetch("https://api.runware.ai/v1", { method: "POST", headers: { "Content-Type": "application/json", Authorization: Bearer ${rwKey} }, body: JSON.stringify([{ taskType: "imageInference", taskUUID: crypto.randomUUID(), positivePrompt: req.prompt, model: "runware:100@1", seedImage: req.imageRefUrl, strength, width: 1024, height: 768, numberResults: 1, outputFormat: "WEBP" }]), signal: ctrl.signal, }); clearTimeout(timer); if (res.ok) { const data = await res.json(); const url = data.data?.[0]?.imageURL || data.data?.[0]?.imageUrl; if (url) { console.log([img2img] Runware OK in ${Date.now() - start}ms); return { model: req.model, provider: "runware-img2img", imageUrl: url, latencyMs: Date.now() - start }; } } } catch (err) { console.log([img2img] Runware error: ${err}); } } // Strategy 3: Luma Photon with image_ref try { console.log([img2img] Trying Luma Photon with image_ref...); const submitRes = await fetch(${LUMA_BASE}/generations/image, { method: "POST", headers: lumaHeaders(), body: JSON.stringify({ prompt: req.prompt, model: "photon-1", aspect_ratio: "4:3", image_ref: [{ url: req.imageRefUrl, weight: strength }] }), }); if (submitRes.ok) { const generation = await submitRes.json(); const genId = generation.id; if (genId) { let elapsed = 0; while (elapsed < 90_000) { await new Promise(r => setTimeout(r, 3_000)); elapsed += 3_000; try { const pollRes = await fetch(${LUMA_BASE}/generations/${genId}, { headers: lumaHeaders() }); if (!pollRes.ok) continue; const pd = await pollRes.json(); if (pd.state === "completed" && pd.assets?.image) { console.log([img2img] Luma OK in ${Date.now() - start}ms); return { model: req.model, provider: "luma/photon-1-img2img", imageUrl: pd.assets.image, latencyMs: Date.now() - start }; } if (pd.state === "failed") throw new Error(Luma failed: ${pd.failure_reason || "unknown"}); } catch (e) { if (e instanceof Error && e.message.startsWith("Luma failed")) throw e; } } } } } catch (err) { console.log([img2img] Luma error: ${err}); } // Final fallback: plain generation (ignore reference) console.log([img2img] All img2img failed, falling back to plain generateImage); return generateImage({ prompt: req.prompt, model: req.model || "ora-vision" }); } // ── VIDEO GENERATION (Luma Ray — submit + polling) ── async function generateVideo(req: { prompt: string; model: string; imageUrl?: string }) { const mapping = videoModelMap[req.model]; if (!mapping) throw new Error(Unknown video model: ${req.model}); const start = Date.now(); const isImg2Vid = !!req.imageUrl; console.log([video] model=${req.model} → Luma ${mapping.lumaModel}, aspect=${mapping.aspectRatio}, img2vid=${isImg2Vid}); console.log([video] prompt="${req.prompt.slice(0, 80)}..."); // Build request body — add keyframes for image-to-video const body: any = { generation_type: "video", prompt: req.prompt, model: mapping.lumaModel, aspect_ratio: mapping.aspectRatio, }; if (req.imageUrl) { body.keyframes = { frame0: { type: "image", url: req.imageUrl }, }; console.log([video] keyframes.frame0.url = ${req.imageUrl.slice(0, 80)}...); } // Step 1: Submit video generation (POST /generations/video per Luma API docs) const submitRes = await fetch(${LUMA_BASE}/generations/video, { method: "POST", headers: lumaHeaders(), body: JSON.stringify(body), }); if (!submitRes.ok) { const b = await submitRes.text(); throw new Error(Luma video submit ${submitRes.status}: ${b}); } const generation = await submitRes.json(); const genId = generation.id; if (!genId) throw new Error(Luma video: no generation id returned: ${JSON.stringify(generation).slice(0, 300)}); console.log([video] Luma generation submitted: ${genId}, state=${generation.state} (${Date.now() - start}ms)); // Step 2: Poll for completion (max 180s, every 5s) let elapsed = 0; while (elapsed < 180_000) { await new Promise(r => setTimeout(r, 5_000)); elapsed += 5_000; try { const pollRes = await fetch(${LUMA_BASE}/generations/${genId}, { headers: lumaHeaders(), }); if (!pollRes.ok) { console.log([video] poll ${pollRes.status} for ${genId} (${elapsed / 1000}s, continuing)); continue; } const pollData = await pollRes.json(); const state = pollData.state; console.log([video] poll ${genId}: state=${state} (${elapsed / 1000}s)); if (state === "completed") { const videoUrl = pollData.assets?.video; if (!videoUrl) throw new Error(Luma video completed but no URL: ${JSON.stringify(pollData).slice(0, 300)}); console.log([video] Luma ${mapping.lumaModel} OK in ${Date.now() - start}ms); return { model: req.model, provider: luma/${mapping.lumaModel}, videoUrl, latencyMs: Date.now() - start }; } if (state === "failed") { throw new Error(Luma video failed: ${pollData.failure_reason || "unknown"}); } // queued, dreaming → continue polling } catch (pollErr) { if (pollErr instanceof Error && (pollErr.message.startsWith("Luma video failed") || pollErr.message.startsWith("Luma video completed"))) throw pollErr; console.log([video] poll error (continuing): ${pollErr}); } } throw new Error(Luma video timeout (180s) for ${mapping.lumaModel}, generation=${genId}); } // ── AUDIO GENERATION (Replicate MusicGen) ──────────────────── async function generateAudio(req: { prompt: string; model: string }) { const repModel = audioModels[req.model]; if (!repModel) throw new Error(Unknown audio model: ${req.model}); const key = Deno.env.get("REPLICATE_API_TOKEN"); if (!key) throw new Error("REPLICATE_API_TOKEN not set"); const start = Date.now(); console.log([audio] ${repModel}); const cr = await fetch(https://api.replicate.com/v1/models/${repModel}/predictions, { method: "POST", headers: { "Content-Type": "application/json", Authorization: Bearer ${key} }, body: JSON.stringify({ input: { prompt: req.prompt, duration: 8, model_version: "stereo-melody-large" } }), }); if (!cr.ok) { const b = await cr.text(); throw new Error(Replicate ${cr.status}: ${b}); } const pred = await cr.json(); if (!pred.id) throw new Error("No prediction ID"); let elapsed = 0; while (elapsed < 120_000) { await new Promise(r => setTimeout(r, 3_000)); elapsed += 3_000; const pr = await fetch(https://api.replicate.com/v1/predictions/${pred.id}, { headers: { Authorization: Bearer ${key} } }); if (!pr.ok) continue; const d = await pr.json(); if (d.status === "succeeded") { const u = typeof d.output === "string" ? d.output : Array.isArray(d.output) ? d.output[0] : null; if (!u) throw new Error("No output URL"); return { model: req.model, provider: replicate/${repModel}, audioUrl: u, latencyMs: Date.now() - start }; } if (d.status === "failed" || d.status === "canceled") throw new Error(Replicate ${d.status}: ${d.error || "unknown"}); } throw new Error("Replicate audio timeout (120s)"); } // ═════════════════════════════════════════════════════════════ // HEALTH // ══════════════════════════════════════════════════════════════ app.get("/health", (c) => { return c.json({ status: "ok", server: "ora-studio-inline", ts: new Date().toISOString(), }); }); // ── TEST APIPOD — minimal direct test ──────────────────────── app.get("/test-apipod", async (c) => { const APIPOD_BASE = "https://api.apipod.ai/v1"; const key = Deno.env.get("APIPOD_API_KEY"); if (!key) return c.json({ error: "APIPOD_API_KEY not set in env" }, 500); const start = Date.now(); try { console.log("[test-apipod] Sending test request..."); const res = await fetch(${APIPOD_BASE}/chat/completions, { method: "POST", headers: { "Content-Type": "application/json", Authorization: Bearer ${key}, }, body: JSON.stringify({ model: "gpt-4o", messages: [ { role: "system", content: "Reply with exactly: OK" }, { role: "user", content: "Test" }, ], max_tokens: 10, }), }); const status = res.status; const body = await res.text(); const latency = Date.now() - start; console.log([test-apipod] status=${status} latency=${latency}ms body=${body.slice(0, 200)}); if (!res.ok) { return c.json({ success: false, error: APIPod returned ${status}, body: body.slice(0, 500), latencyMs: latency, keyPrefix: key.slice(0, 8) + "...", }); } let parsed: any; try { parsed = JSON.parse(body); } catch { parsed = null; } const text = parsed?.choices?.[0]?.message?.content || "(no content)"; return c.json({ success: true, text, model: parsed?.model || "unknown", tokensUsed: parsed?.usage?.total_tokens || 0, latencyMs: latency, keyPrefix: key.slice(0, 8) + "...", }); } catch (err) { return c.json({ success: false, error: Exception: ${err instanceof Error ? err.message : String(err)}, latencyMs: Date.now() - start, keyPrefix: key.slice(0, 8) + "...", }); } }); // ══════════════════════════════════════════════════════════════ // AUTH ROUTES // ══════════════════════════════════════════════════════════════ app.post("/auth/signup", async (c) => { try { const { email, password, name } = await c.req.json(); if (!email || !password) return c.json({ error: "Email and password required" }, 400); const sb = supabaseAdmin(); const { data, error } = await sb.auth.admin.createUser({ email, password, user_metadata: { name: name || email.split("@")[0] }, email_confirm: true, }); if (error) { console.log("[signup] error:", error.message); return c.json({ error: error.message }); } if (data.user) { await getOrCreateProfile(data.user.id, email, name); await logEvent("signup", { email, userId: data.user.id }); } return c.json({ success: true, user: { id: data.user?.id, email } }); } catch (err) { console.log("[signup] exception:", err); return c.json({ error: Signup error: ${err} }, 500); } }); // POST /auth/me — preferred: user token in body.token (avoids CORS issues) app.post("/auth/me", async (c) => { const t0 = Date.now(); console.log("[/auth/me POST] request received"); try { const result = await Promise.race([ (async () => { const user = await requireAuth(c); console.log([/auth/me POST] auth OK (${Date.now() - t0}ms), fetching profile...); const profile = await getOrCreateProfile(user.id, user.email); profile.lastLoginAt = new Date().toISOString(); kv.set(user:${user.id}, profile).catch((e: any) => console.log("[/auth/me POST] kv.set lastLogin failed:", e)); return c.json({ authenticated: true, profile }); })(), new Promise((, reject) => setTimeout(() => reject(new Error("auth/me handler timeout (8s)")), 8_000)), ]); return result; } catch (err) { console.log([/auth/me POST] error after ${Date.now() - t0}ms:, String(err)); // Fallback: decode JWT from body.token try { const bodyToken = c.get?.("userToken"); if (bodyToken) { const payload = decodeJwtPayload(bodyToken); if (payload?.sub && payload?.email) { const isAdmin = payload.email.toLowerCase() === ADMIN_EMAIL; return c.json({ authenticated: true, profile: { userId: payload.sub, email: payload.email, name: payload.user_metadata?.name || payload.email.split("@")[0], role: isAdmin ? "admin" : "user", plan: isAdmin ? "studio" : "free", credits: isAdmin ? 999999 : PLAN_CREDITS.free, creditsUsed: 0, company: "", jobTitle: "", createdAt: new Date().toISOString(), lastLoginAt: new Date().toISOString(), fallback: true, }, }); } } } catch (e2) { console.log("[/auth/me POST] fallback also failed:", e2); } return c.json({ authenticated: false, error: String(err) }); } }); // GET /auth/me — legacy (kept for backward compat) app.get("/auth/me", async (c) => { const t0 = Date.now(); const userToken = c.req.header("Authorization")?.split(" ")[1] || c.req.header("X-User-Token"); console.log("[/auth/me] request received, has Authorization:", !!c.req.header("Authorization")); try { // Wrap entire handler in a 8s timeout to prevent infinite hangs const result = await Promise.race([ (async () => { const user = await requireAuth(c); console.log([/auth/me] auth OK (${Date.now() - t0}ms), fetching profile...); const profile = await getOrCreateProfile(user.id, user.email); console.log([/auth/me] profile OK (${Date.now() - t0}ms)); profile.lastLoginAt = new Date().toISOString(); // Fire-and-forget the lastLogin update (don't block response) kv.set(user:${user.id}, profile).catch((e: any) => console.log("[/auth/me] kv.set lastLogin failed:", e)); return c.json({ authenticated: true, profile }); })(), new Promise((, reject) => setTimeout(() => reject(new Error("auth/me handler timeout (8s)")), 8_000)), ]); return result; } catch (err) { console.log([/auth/me] error after ${Date.now() - t0}ms:, String(err)); // If timeout or KV failure, try to return basic info from JWT alone try { if (userToken) { const payload = decodeJwtPayload(userToken); if (payload?.sub && payload?.email) { const isAdmin = payload.email.toLowerCase() === ADMIN_EMAIL; return c.json({ authenticated: true, 