lCount++; totalCostEur += entry.costEur || 0; totalRevenue += entry.revenueEur || 0; totalMargin += entry.marginEur || 0; // By provider const pKey = entry.provider.split("/")[0]; // luma, replicate, apipod if (!byProvider[pKey]) byProvider[pKey] = { count: 0, totalCostUsd: 0, totalCostEur: 0, totalRevenue: 0, totalMargin: 0, avgLatency: 0, successCount: 0, failCount: 0 }; const bp = byProvider[pKey]; bp.count++; bp.totalCostUsd += entry.costUsd || 0; bp.totalCostEur += entry.costEur || 0; bp.totalRevenue += entry.revenueEur || 0; bp.totalMargin += entry.marginEur || 0; bp.avgLatency = (bp.avgLatency * (bp.count - 1) + (entry.latencyMs || 0)) / bp.count; if (entry.success) bp.successCount++; else bp.failCount++; // By type if (!byType[entry.type]) byType[entry.type] = { count: 0, totalCostEur: 0, totalRevenue: 0, totalMargin: 0 }; const bt = byType[entry.type]; bt.count++; bt.totalCostEur += entry.costEur || 0; bt.totalRevenue += entry.revenueEur || 0; bt.totalMargin += entry.marginEur || 0; // By day const day = entry.timestamp?.slice(0, 10) || "unknown"; if (!byDay[day]) byDay[day] = { costEur: 0, revenueEur: 0, marginEur: 0, count: 0 }; byDay[day].costEur += entry.costEur || 0; byDay[day].revenueEur += entry.revenueEur || 0; byDay[day].marginEur += entry.marginEur || 0; byDay[day].count++; } // Round values for (const k of Object.keys(byProvider)) { const p = byProvider[k]; p.totalCostUsd = Math.round(p.totalCostUsd * 10000) / 10000; p.totalCostEur = Math.round(p.totalCostEur * 10000) / 10000; p.totalRevenue = Math.round(p.totalRevenue * 10000) / 10000; p.totalMargin = Math.round(p.totalMargin * 10000) / 10000; p.avgLatency = Math.round(p.avgLatency); } return c.json({ success: true, costs: { total: { count: totalCount, costEur: Math.round(totalCostEur * 10000) / 10000, revenueEur: Math.round(totalRevenue * 10000) / 10000, marginEur: Math.round(totalMargin * 10000) / 10000 }, byProvider, byType, byDay, recentEntries: sorted.slice(0, 100), providerCostTable: PROVI